def maximum_jumps(nums, target):
    n = len(nums)
    dp = [-1] * n
    dp[0] = 0

    for i in range(n):
        if dp[i] == -1:
            continue
        for j in range(i + 1, n):
            if -target <= nums[j] - nums[i] <= target:
                dp[j] = max(dp[j], dp[i] + 1)

    return dp[n - 1]
